import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiShield, 
  FiArrowLeft, 
  FiUsers, 
  FiCalendar, 
  FiDollarSign,
  FiTrendingUp,
  FiUserPlus,
  FiSettings,
  FiLogOut,
  FiBarChart,
  FiCheckCircle,
  FiClock,
  FiXCircle,
  FiEye,
  FiPackage,
  FiGift,
  FiX
} from 'react-icons/fi';
import { MdVisibility, MdReply, MdViewList, MdViewModule, MdSearch, MdFilterList } from 'react-icons/md';
import { useAuth } from '../context/AuthContext';
import { Booking, Employee, ContactQuery } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS, API_BASE_URL } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';
import axios from 'axios';
import { getApiUrl } from '../config/api';
import Modal from '../components/Modal'; // Added Modal import

const AdminDashboard: React.FC = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'overview' | 'bookings' | 'employees' | 'queries' | 'services' | 'offers'>('overview');
  const [bookingsTab, setBookingsTab] = useState<'all' | 'pending' | 'accepted' | 'completed'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [assignTechId, setAssignTechId] = useState<string>('');
  const [assignLoading, setAssignLoading] = useState(false);
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [queryViewMode, setQueryViewMode] = useState<'table' | 'card'>('table');
  const [showQueryModal, setShowQueryModal] = useState(false);
  const [showRespondModal, setShowRespondModal] = useState(false);
  const [selectedQuery, setSelectedQuery] = useState<any>(null);
  const [respondText, setRespondText] = useState('');
  const [respondLoading, setRespondLoading] = useState(false);
